// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// always hide the setting field
	g_form.setDisplay('u_template_subtask_s_name_setting',false);

	if (isLoading || newValue === '') {
		// DFCT0010561
		setLoadMessage();
		return;
	} else {
		setLoadMessage();
		return;
	}

	// DFCT0010561
	function setLoadMessage(){

		var subtaskSettingIsNone = (g_scratchpad.u_template_subtask_s_name_setting == null ||
									g_scratchpad.u_template_subtask_s_name_setting == '' || 
									g_scratchpad.u_template_subtask_s_name_setting == 'None');
		g_form.setMandatory('u_subtask_s_name_modifier', !subtaskSettingIsNone);
		g_form.setDisplay('u_subtask_s_name_modifier', !subtaskSettingIsNone);

		if((g_form.getValue('u_subtask_s_name_modifier') + '') == ''){
			if(g_scratchpad.u_template_subtask_s_name_setting == 'prefix'){
				g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - Enter a value to apply a Prefix to the Task Name of all Subtasks'), 'info');
			} else if(g_scratchpad.u_template_subtask_s_name_setting == 'suffix'){
				g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - Enter a value to apply a Suffix to the Task Name of all Subtasks'), 'info');
			}			
		} else {
			if(g_scratchpad.u_template_subtask_s_name_setting == 'prefix'){
				g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - The value entered will apply as a Prefix to the Task Name of all Subtasks'), 'info');
			} else if(g_scratchpad.u_template_subtask_s_name_setting == 'suffix'){
				g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - The value entered will apply as a Suffix to the Task Name of all Subtasks'), 'info');
			}			
		}

	}

}
